import csv, json, math, sys
from collections import defaultdict, Counter

path = "exp8_csv_small/csv/freight_rail_operations_1_1.csv"

# Determine likely column names
hp_key = None
param_key = None
try:
    with open(path, 'r', encoding='utf-8', newline='') as f:
        reader = csv.DictReader(f)
        fields = reader.fieldnames or []
        # heuristic: hyper_param-like name
        hp_candidates = [f for f in fields if 'hyper' in f.lower() and 'param' in f.lower()]
        param_candidates = [f for f in fields if 'param' in f.lower() and 'json' in f.lower()]
        if hp_candidates:
            hp_key = hp_candidates[0]
        if param_candidates:
            param_key = param_candidates[0]
        # fallbacks
        if not hp_key and fields:
            for f in fields:
                if 'hyper_param' in f or 'hyper-param' in f:
                    hp_key = f
                    break
        if not param_key:
            for f in fields:
                if 'params' in f.lower() and 'json' in f.lower():
                    param_key = f
                    break
        if not hp_key:
            hp_key = 'hyper_param_index' if 'hyper_param_index' in fields else fields[0]
        if not param_key:
            param_key = 'params_json' if 'params_json' in fields else (fields[1] if len(fields) > 1 else None)
        # finalize
        if not param_key:
            print("Could not determine a params JSON column. Exiting.", file=sys.stderr)
            sys.exit(1)
        if not hp_key:
            print("Could not determine a hyper-parameter index column. Exiting.", file=sys.stderr)
            sys.exit(1)
except FileNotFoundError:
    print("CSV file not found at path: {}".format(path), file=sys.stderr)
    sys.exit(1)

hyper_indices = set()
per_index_params = defaultdict(list)
row_counts = Counter()

# Read data
with open(path, 'r', encoding='utf-8', newline='') as f:
    reader = csv.DictReader(f)
    for i, row in enumerate(reader, 1):
        hp = row.get(hp_key)
        if hp is None:
            continue
        hyper_indices.add(str(hp))
        param_str = row.get(param_key)
        if param_str is None:
            continue
        try:
            d = json.loads(param_str)
        except Exception:
            # If the json is not valid, skip
            continue
        if isinstance(d, dict):
            per_index_params[str(hp)].append(d)
        # update row count if possible
        row_counts[str(hp)] += 1

# Helper to extract numeric value
def to_number(x):
    if isinstance(x, (int, float)):
        return float(x)
    if isinstance(x, bool):
        return float(int(x))
    if isinstance(x, str):
        try:
            return float(x)
        except:
            return None
    return None

# Collect all keys across all param dicts
all_keys = set()
for idx, dicts in per_index_params.items():
    for d in dicts:
        if isinstance(d, dict):
